import React, { useState } from 'react';
import { Button, Select, DateRangeFilter, addToast } from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { hrService } from '../../../services/ns/hrService';
import type { AttendanceRecordDto, DepartmentDto } from '../../../services/ns/models';
import { formatDateLocal } from '../../../utils/format';
import styles from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

type ViewMode = 'summary' | 'detail';

interface SummaryRow {
  employeeId: string;
  employeeName: string;
  lateTimes: number;
  absentTimes: number;
}

function aggregateByEmployee(rows: AttendanceRecordDto[]): SummaryRow[] {
  const map: Record<string, SummaryRow> = {};
  for (const r of rows) {
    if (!map[r.employeeId]) {
      map[r.employeeId] = { employeeId: r.employeeId, employeeName: r.employeeName, lateTimes: 0, absentTimes: 0 };
    }
    if (r.isLate) map[r.employeeId].lateTimes += 1;
  }
  return Object.values(map).filter(x => x.lateTimes > 0);
}

const BaoCaoDiTrePage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const now = new Date();
  const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().slice(0, 10);
  const monthEnd = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().slice(0, 10);

  const [fromDate, setFromDate] = useState(monthStart);
  const [toDate, setToDate] = useState(monthEnd);
  const [departmentId, setDepartmentId] = useState('');
  const [view, setView] = useState<ViewMode>('summary');
  const [depts, setDepts] = useState<DepartmentDto[]>([]);
  const [rows, setRows] = useState<AttendanceRecordDto[]>([]);
  const [loading, setLoading] = useState(false);
  const handleSearch = () => setReloadKey(k => k + 1);
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      hrService.getDepartments().then(d => { if (!cancelled) setDepts(d); }).catch(() => {});
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, []);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      hrService.getLateReport({ fromDate, toDate, departmentId: departmentId || undefined })
        .then(res => { if (!cancelled) setRows(res.items); })
        .catch(err => {
          if (!cancelled)
            dispatch(addToast({ message: err?.message ?? 'Lỗi tải báo cáo', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [fromDate, toDate, departmentId, dispatch, reloadKey]);

  const summaryRows = aggregateByEmployee(rows);
  const detailRows = rows.filter(r => r.isLate);

  const handleExport = () => {
    const qs = new URLSearchParams({ fromDate, toDate });
    if (departmentId) qs.set('departmentId', departmentId);
    const a = document.createElement('a');
    a.href = `${import.meta.env.VITE_API_URL}/hr/attendance/late-report/export-excel?${qs}`;
    a.download = 'BaoCaoDiTre.xlsx';
    a.click();
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-user-clock" /> Báo cáo đi trễ / về sớm</h1>
        </div>
        <div className={styles.headerActions}>
          <Button variant="secondary" onClick={handleExport}><i className="fas fa-file-excel" /> Xuất Excel</Button>
        </div>
      </div>

      <div className={styles.filtersBar} data-testid={`erp-bao-cao-di-tre-filters`}>
        <DateRangeFilter
          fromDate={fromDate}
          toDate={toDate}
          onChange={(v: DateRangeValue) => { setFromDate(v.fromDate ?? ''); setToDate(v.toDate ?? ''); }}
        />
        <Select
          value={departmentId}
          onChange={e => setDepartmentId(e.target.value)}
          options={[{ value: '', label: 'Tất cả đơn vị' }, ...depts.map(d => ({ value: d.id, label: `${d.code} — ${d.name}` }))]}
          size="small"
        />
        <Select
          value={view}
          onChange={e => setView(e.target.value as ViewMode)}
          options={[
            { value: 'summary', label: 'Tổng hợp' },
            { value: 'detail', label: 'Chi tiết' },
          ]}
          size="small"
        />
        <ListSearchRefreshButtons testIdPrefix="erp-bao-cao-di-tre" onSearch={handleSearch} onRefresh={refresh} showSearch={false} />
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : view === 'summary' ? (
          summaryRows.length === 0 ? (
            <div className={styles.empty}><p>Không có dữ liệu</p></div>
          ) : (
            <div className={styles.tableWrapper}>
              <table className={styles.table}>
                <thead>
                  <tr><th>Họ tên</th><th className={styles.colRight}>Số lần trễ</th></tr>
                </thead>
                <tbody>
                  {summaryRows.map(r => (
                    <tr key={r.employeeId}>
                      <td>{r.employeeName}</td>
                      <td className={styles.colRight}><span className={styles.tagWarning}>{r.lateTimes}</span></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )
        ) : detailRows.length === 0 ? (
          <div className={styles.empty}><p>Không có bản ghi</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr><th>Ngày</th><th>Họ tên</th><th>TT</th></tr>
              </thead>
              <tbody>
                {detailRows.map(r => (
                  <tr key={r.id}>
                    <td>{formatDateLocal(r.attendanceDate)}</td>
                    <td>{r.employeeName}</td>
                    <td><span className={styles.tagWarning}>Đi trễ</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default BaoCaoDiTrePage;
